<template>
  <div ref="charts" style="height:100%;width:100%"></div>
</template>

<script setup>
import * as echarts from "echarts";
import { onMounted, ref, watch } from "vue-demi";
const charts = ref(null);
const props = defineProps({
  count: Number,
  status: Object,
});
let chartDom;
let option = {
 grid: [
    { left: "2%", top: "8%", width: "95%", height: "4%" },
    { left: "2%", top: "26%", width: "95%", height: "4%" },
    { left: "2%", top: "44%", width: "95%", height: "4%" },
    { left: "2%", top: "62%", width: "95%", height: "4%" },
    { left: "2%", top: "80%", width: "95%", height: "4%" },
  ],
  xAxis: [
    {
      gridIndex: 0,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 1,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 2,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 3,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 4,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
  ],
  // xAxis: {
  //   type: "category",
  //   data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
  // },
  legend: {
    top: 18,
    textStyle: {
      fontSize: 15,
    },
    data: [],
  },
  tooltip: {
    trigger: "axis",
    axisPointer: {
      type: "shadow",
    },
    valueFormatter: (value) => "",
  },
  yAxis: [
    {
      gridIndex: 0,
      minInterval: 1,
      nameGap: 0,
      name: "CAN",
    },
    {
      gridIndex: 1,
      minInterval: 1,
      nameGap: 0,
      name: "WIFI",
    },
    {
      gridIndex: 2,
      nameGap: 0,
      minInterval: 1,
      name: "急停",
    },
    {
      gridIndex: 3,
      minInterval: 1,
      nameGap: 0,
      name: "闭锁",
    },
    {
      gridIndex:4,
      minInterval: 1,
      nameGap: 0,
      name: "Lin",
    },
  ],
  // yAxis: {
  //   type: "value",
  //   show: false,
  // },
  // series: [{ name: props.name, data: [], type: "bar" }],
  series: [
    {
      name: "CAN",
      type: "bar",
      xAxisIndex: 0,
      yAxisIndex: 0,
      itemStyle: {
        color: "#4FD000",
      },
      lineStyle: {
        color: "#555",
        width: 3,
      },
      tooltip: {
        textStyle: {
          fontSize: 15,
        },
        formatter: "<center>{a0}</center>{b0}号支架: {c0}(mm)",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },
      data: [],
    },
    {
      name: "WIFI",
      type: "bar",
      xAxisIndex: 1,
      yAxisIndex: 1,
      itemStyle: {
        color: "#4FD000",
      },
      tooltip: {
        textStyle: {
          fontSize: 15,
        },
        formatter: "<center>{a0}</center>{b0}号支架: {c0}(MBar)",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },
      markLine: {},
      data: [],
    },
    {
      name: "急停",
      type: "bar",
      xAxisIndex: 2,
      yAxisIndex: 2,
      itemStyle: {
        color: "#4FD000",
      },
      tooltip: {
        textStyle: {
          fontSize: 15,
        },
        formatter: "<center>{a0}</center>{b0}号支架: {c0}(MBar)",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },
      markLine: {},
      data: [],
    },
    {
      name: "闭锁",
      type: "bar",
      xAxisIndex: 3,
      yAxisIndex: 3,
      itemStyle: {
        color: "#4FD000",
      },
      tooltip: {
        textStyle: {
          fontSize: 15,
        },
        formatter: "<center>{a0}</center>{b0}号支架: {c0}(mm)",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },

      data: [],
    },
    {
      name: "Lin状态",
      type: "bar",
      xAxisIndex: 4,
      yAxisIndex: 4,
      itemStyle: {
        color: "#4FD000",
      },
      tooltip: {
        textStyle: {
          fontSize: 15,
        },
        formatter: "<center>{a0}</center>{b0}号支架: {c0}(mm)",
      },
      animationDelay: function (idx) {
        return idx * 5;
      },

      data: [],
    },
  ],
};
const reDraw = () => {
  option.series[0].data = [1, 1, 1, 1, 1, 1];
  chartDom.setOption(option);
  chartDom.resize();
};

watch(
  () => props.count,
  (val) => {
    option.xAxis =  [
    {
      gridIndex: 0,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 1,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 2,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
    {
      gridIndex: 3,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    }
    ,
    {
      gridIndex: 4,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    }
    ]
    chartDom.setOption(option);
    chartDom.resize();
  })
watch(
  () => props.status,
  (val) => {
    console.log("内部",val)
    if (typeof val.can == "object" && val.can.length >0) {
      let data = [];
      for (let index = 0; index < val.can.length; index++) {
        const element = val.can[index];
        if (element == 0) {
          data.push(1);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#a90000",
            },
          });
        }
      }
      option.series[0].data = data;
    }
    if (typeof val.wifi == "object" && val.wifi.length >0) {
      let data = [];
      for (let index = 0; index < val.wifi.length; index++) {
        const element = val.wifi[index];
        if (element == 0) {
          data.push(1);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#a90000",
            },
          });
        }
      }
      option.series[1].data = data;
    }
    if (typeof val.emergency == "object" && val.emergency.length >0) {
      let data = [];
      for (let index = 0; index < val.emergency.length; index++) {
        const element = val.emergency[index];
        if (element == 0) {
          data.push(1);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#a90000",
            },
          });
        }
      }
      option.series[2].data = data;
    }
    if (typeof val.lock == "object" && val.lock.length >0) {
      let data = [];
      for (let index = 0; index < val.lock.length; index++) {
        const element = val.lock[index];
        if (element == 0) {
          data.push(1);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#a90000",
            },
          });
        }
      }
      option.series[3].data = data;
    }
    if (typeof val.linstate == "object" && val.linstate.length >0) {
      let data = [];
      for (let index = 0; index < val.linstate.length; index++) {
        const element = val.linstate[index];
        if (element == 0) {
          data.push(1);
        }
        if (element == 1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#a90000",
            },
          });
        }
      }
      option.series[4].data = data;
    }
    chartDom.setOption(option);
    chartDom.resize();
  },
  {
    deep: true,
  }

);
onMounted(() => {
  chartDom = echarts.init(charts.value);
  reDraw();
});
</script>

