<template>
  <div ref="charts" style="height:100%;width:100%"></div>
</template>

<script setup>
import * as echarts from "echarts";
import { onMounted, ref, watch } from "vue-demi";
const charts = ref(null);
const props = defineProps({
  count: Number,
  status: Object,
});
let chartDom;
let option = {
  grid: [{ left: "2%", top: "45%", width: "95%", height: "25%" }],
  xAxis: [
    {
      gridIndex: 0,
      min: 0,
      data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
    },
  ],

  legend: {
    top: 18,
    textStyle: {
      fontSize: 15,
    },
    data: [],
  },
  tooltip: {
    trigger: "axis",
    axisPointer: {
      type: "shadow",
    },
    valueFormatter: (value) => "",
  },
  yAxis: [
    {
      gridIndex: 0,
      minInterval: 1,
      nameGap: 0,
      name: "煤机位置",
    },
  ],

  series: [
    {
      name: "煤机位置",
      type: "bar",
      xAxisIndex: 0,
      yAxisIndex: 0,
      itemStyle: {
        color: "#4FD000",
      },
      lineStyle: {
        color: "#555",
        width: 3,
      },
      animationDelay: function (idx) {
        return idx * 5;
      },
      data: [],
    },
  ],
};


const reDraw = () => {
  option.series[0].data = [];
  chartDom.setOption(option);
  chartDom.resize();
};

watch(
  () => props.count,
  (val) => {
    //console.log("监听到值的变化",props.count)


    option.xAxis =  [
    {
      gridIndex: 0,
      min: 0,
      data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
    },
  ]
  chartDom.setOption(option);
  chartDom.resize();
  }
);



watch(
  () => props.status,
  (val) => {
    if (
      typeof val == "object" &&
      val.length > 0
    ) {
      let data = [];
      for (
        let index = 0;
        index < val.length;
        index++
      ) {
        const element = val[index];
        if (element == 0) {
          data.push(0);
        }
        if (element==1) {
          data.push({
            value: 1,
            itemStyle: {
              color: "#0000a9",
            },
          });
        }
        
      }
      option.series[0].data = data;
    }

    chartDom.setOption(option);
    chartDom.resize();
  },
  {
    deep: true,
  }
);
onMounted(() => {
  chartDom = echarts.init(charts.value);
  reDraw();
});
</script>

