<template>
  <div ref="charts" style="height:100%;width:100%"></div>
</template>

<script setup>
import * as echarts from "echarts";
import { onMounted, ref, watch } from "vue-demi";
const charts = ref(null);
const props = defineProps({
  count: Number,
  max: Number,
  status: Object,
  name: String,
});
let chartDom;
let option = {
  grid: {
    left: "2%",
    top: "20%",
    width: "95%",
    height: "65%",
  },
  visualMap: {
    show: false,
    pieces: [
      {
        gt: 0,
        lte: 999,
        color: "#4e72b8",
      }
    ],
    outOfRange: {
      color: "#B71C1C",
    },
  },
  xAxis: {
    type: "category",
    min: 0,
    data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
  },
  legend: {
    top: 18,
    textStyle: {
      fontSize: 15,
    },
    data: [],
  },
  tooltip: {
    trigger: "axis",
    axisPointer: {
      type: "shadow",
    },
    valueFormatter: (value) => value + "mm",
  },
  yAxis: {
    type: "value",
    min: 0,
    max: props.max,
    nameGap: 5,
    name: props.name,
  },
  // yAxis: {
  //   type: "value",
  //   show: false,
  // },
  series: [{ name: props.name, data: [], type: "bar" }],
};
const reDraw = () => {
  option.series[0].data = [1, 1, 1, 1, 1, 1];
  chartDom.setOption(option);
  chartDom.resize();
};

watch(
  () => props.count,
  (val) => {
    option.xAxis =  {
    type: "category",
    min: 0,
    data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
  }
  chartDom.setOption(option);
    chartDom.resize();
  }
  )

watch(
  () => props.status,
  (val) => {
    option.series[0].data = props.status;
    chartDom.setOption(option);
    chartDom.resize();
  },
  {
    deep: true,
  }
);
onMounted(() => {
  chartDom = echarts.init(charts.value);
  reDraw();
});
</script>

