<template>
  <n-layout class="content">
    <n-layout-content class="content-center">
        <n-grid cols="1 s:2 m:6 l:6 xl:6 2xl:`12`" item-responsive responsive="screen">
        <n-gi span="6">
         
          <n-divider dashed style="height:0px">煤机数据</n-divider>
          
          <n-space justify="center">
            <n-descriptions
                label-placement="left"
                bordered
                :column="6"
                label-align="center"
                size="small"
              >
              <n-descriptions-item label="左截割高度(mm)">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{left_roll_height}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="服务器心跳">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{heart}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="采煤机速度(m/min)">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{speed}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="采煤机工步">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{step}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="CAN1数据负载率">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{can_load_rate1}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="支架自动化状态">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{autoStatus}}</span>
                  </n-space>
                </n-descriptions-item>
            
                <n-descriptions-item label="右截割高度(mm)">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{right_roll_height}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="采煤机方向">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{direction}}</span>
                  </n-space>
                </n-descriptions-item>
                
                <n-descriptions-item label="采煤机位置(架)">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{position}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="人员接近闭锁使能">
                  <n-switch
                    :disabled=personEnable
                    :loading=personEnable
                    size="small"
                    :value="shearerData.data.person_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="newMethod"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                
                <n-descriptions-item label="CAN2数据负载率">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{can_load_rate2}}</span>
                  </n-space>
                </n-descriptions-item>
                <n-descriptions-item label="支架远控使能">
                  <n-switch
                    
                    :disabled=autoEnable
                    :loading=autoEnable
                    size="small"
                    :value="shearerData.data.auto_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="newMethod1"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
            
          </n-descriptions>
        
          </n-space>
        </n-gi>
      </n-grid>
        <value-charts
          :count="counts"
          style="top:-2%;height:13%;width:100%;"
          :name="'左立柱压力'"
          :max="504"
          :status="valueChartData.left_pressure"
          :statustime = "valueChartData.left_pressure_time"
          :statustimeinterval = "valueChartData.left_pressure_time_interval"
        ></value-charts>
        <!-- <value-charts
          :count="counts"
          style="height:120px;width:100%;"
          :name="'右立柱压力'"
          :max="600"
          :status="valueChartData.right_pressure"
        ></value-charts> -->
        <distancebad-charts
          :count="counts"
          style="top:-2%;height:7%;width:100%;"
          :name="'行程传感器故障'"
          :max="1"
          :status="distanceBad"
        ></distancebad-charts>
        <distance-charts
          :count="counts"
          style="top:-2%;height:13%;width:100%;"
          :name="'推移行程'"
          :max="1000"
          :status="valueChartData.push_itinerary"
        ></distance-charts>
        <autofollow-charts
          :count="counts"
          style="top:-2%;height:7%;width:100%;"
          :name="'煤机位置'"
          :max="1"
          :status="shearerPosition"
        ></autofollow-charts>
        <cqlj-charts
          :count="counts"
          style="top:-2%;height:7%;width:100%;"
          :name="'超前拉架警示'"
          :max="1"
          :status="complateChartData.cqlj"
        ></cqlj-charts>
        <action-charts :count="counts" style="top:-2%;height:23%;width:100%;" :status="complateChartData"></action-charts>
        <status-charts :count="counts" style="bottom:2%;height:22%;width:100%;" :status="statusChartData"></status-charts>
        <high-charts
              :count="counts"
              style="top:-2%;height:13%;width:100%;"
              :name="'工作面采高'"
              :max="3000"
              :status="valueChartData.roof_height"
        ></high-charts>
 
    </n-layout-content>
    
    <!-- <n-layout-footer bordered position="absolute" class="content-footer">
      <supports :active="support" :total="counts" @selected="selectSupport"></supports>
    </n-layout-footer> -->
  </n-layout>
</template>

<script setup>
import ValueCharts from "./components/value-echarts.vue";
import DistanceCharts from "./components/distance-echarts.vue";
import ActionCharts from "./components/action-echarts.vue";
import StatusCharts from "./components/status-echarts.vue";
import AutofollowCharts from "./components/autofollow-echarts.vue";
import DistancebadCharts from "./components/distancebad-echarts.vue";
import CqljCharts from "./components/cqlj-echarts.vue";
import HighCharts from "./components/high-echarts.vue";
import { h, ref, reactive, computed, onMounted, watch } from "vue";
import { setPersonEnable,getSupportNum,setAutoEnable} from "../../api/request";
import supports from "../../components/supports.vue";
import { useWsStore } from "../../store/modules/websocket";
import { useNotification } from 'naive-ui'
import 'echarts-gl';


const rns = ref(1)

function newMethod(i){
  shearerData.data.person_enable = i
  setPersonEnable({ value: i});
}


function newMethod1(i){
  shearerData.data.auto_enable = i
  setAutoEnable({ value: i});
}
const support = ref(1);
const counts = ref(0);
const personEnable = ref(false);
const autoEnable = ref(false);
const shearerPosition = ref([])
const distanceBad = ref([])
const selectSupport = async (va) => {
  support.value = va;
};
const statusChartData = reactive({
  can: [],
  wifi: [],
  lock: [],
  emergency: [],
  linstate: [],
  
});

const shearerData = reactive({
  data: {
  step:0,
  position:0,
  speed:0,
  direction:0,
  left_roll_height:0,
  right_roll_height:0,
  heart:"",
  person_enable:0,
  can_load_rate1:0,
  can_load_rate1:0,  
  sort:0,
  auto_status:0,
  auto_enable:0,
},
});
const valueChartData = reactive({
  left_pressure: [],
  right_pressure: [],
  push_itinerary: [],
  roof_height: [],
  left_pressure_time:[],
  left_pressure_time_interval:[],
});
const complateChartData = reactive({
  complete_automatic_push: [], // 完成自动推溜
  complete_automatic_rack_transfer: [], // 完成自动移架
  complete_automatic_care: [], // 完成自动收护帮板
  complete_automatic_extension: [], // 完成自动伸护帮板
  cqlj: [],
});
const wsStore = useWsStore();
watch(
  () => wsStore.faultStatus,
  (val) => {
    console.log("故障",val)
    statusChartData.can = val.can_arr;
    statusChartData.wifi = val.wifi_arr;
    statusChartData.lock = val.lock_arr;
    statusChartData.emergency = val.emergency_stop_arr;
    statusChartData.credible = val.credible;
    statusChartData.linstate = val.lin_arr;
  }
);
watch(
  () => wsStore.autoFollowStatus,
  (val) => {
    
    complateChartData.auto_follow = val.is_auto_follow;
    complateChartData.complete_automatic_push = val.complete_automatic_push;
    complateChartData.complete_automatic_rack_transfer =val.complete_automatic_rack_transfer;
    complateChartData.complete_automatic_care = val.complete_automatic_care;
    complateChartData.complete_automatic_extension =val.complete_automatic_extension;
    complateChartData.cqlj = val.cqlj
    //console.log("超前拉架",complateChartData.cqlj )
  }
);
watch(
  () => wsStore.simulationStatus,
  (val) => {
    valueChartData.left_pressure = val.column_pressure_left;
    valueChartData.right_pressure = val.column_pressure_right;
    valueChartData.push_itinerary = val.push_itinerary;
    valueChartData.roof_height = val.roof_height;
    valueChartData.left_pressure_time = val.column_pressure_left_time;
    valueChartData.left_pressure_time_interval =val.column_pressure_left_time_interval 
    distanceBad.value = []
     for(var i=0;i<counts.value;i++){
      if (val.voltage_12v[i]>0){
        distanceBad.value.push(1)
      }else{
        distanceBad.value.push(0)
      }
    }
    console.log("行程传感器损坏val",val)
    console.log("行程传感器损坏",distanceBad.value)
  }
);
const step = ref("");
const position = ref("");
const speed = ref("");
const direction = ref("");
const left_roll_height = ref("");
const right_roll_height = ref("");
const heart = ref("");
const can_load_rate1 = ref("");
const can_load_rate2 = ref("");
const autoStatus = ref("");
const auto_enable = ref("");
watch(
  () => wsStore.shearer,
  (val) => {

    shearerData.data = val
    personEnable.value =false
    step.value = shearerData.data.step.toString();
    position.value = (shearerData.data.position/10).toString();
    speed.value = (shearerData.data.speed/10).toString();
    if(shearerData.data.auto_status==0){
      autoStatus.value = "手动"    
    }else if (shearerData.data.auto_status==1){
      autoStatus.value = "自动"
    }
   
    if (shearerData.data.sort==0){
      if (shearerData.data.direction==0){
      direction.value="机头"
    }else if (shearerData.data.direction==1){
      direction.value="机尾"
    }else{
      direction.value="异常"
    }
    }else{
      if (shearerData.data.direction==0){
      direction.value="机尾"
    }else if (shearerData.data.direction==1){
      direction.value="机头"
    }else{
      direction.value="异常"
    }
    }
    
    shearerPosition.value = []
    //console.log("煤机位置",i, shearerData.data.position/10,i== shearerData.data.position/10)
    for(var i=0;i<counts.value;i++){
      //console.log("煤机位置",i, shearerData.data.position/10,i== shearerData.data.position/10)
      if (i<= Math.floor(shearerData.data.position/10)+3 && i>= Math.floor(shearerData.data.position/10)-5){
        shearerPosition.value.push(1)
      }else{
        shearerPosition.value.push(0)
      }
    }
   
    
    left_roll_height.value = shearerData.data.left_roll_height.toString();
    right_roll_height.value = shearerData.data.right_roll_height.toString();
    heart.value =  shearerData.data.heart.toString();
    can_load_rate1.value = (shearerData.data.can_load_rate1/10).toString()+"%";
    can_load_rate2.value = (shearerData.data.can_load_rate2/10).toString()+"%";
  }
);

onMounted(async () => {
  let {code,message} = await getSupportNum();
  counts.value = message

});
</script>

<style lang="scss" scoped>
.content {
  height: 100%;
  position: relative;
  &-center {
    position: absolute;
    top: 0;
    width: 100%;
    bottom: 0px;
  }
  &-footer {
    height: 56px;
    color: #cba;
    text-align: center;
    position: absolute;
    bottom: 0px;
    width: 100%;
  }
}
</style>